def encrypt(s):
    result = []
    for char in s:
        if char.isalpha():
            # Determine if uppercase or lowercase
            if char.isupper():
                base = ord('A')
                offset = ord(char) - base
                # Shift by 2 * 2 = 4 positions
                new_offset = (offset + 4) % 26
                result.append(chr(base + new_offset))
            else:
                base = ord('a')
                offset = ord(char) - base
                # Shift by 2 * 2 = 4 positions
                new_offset = (offset + 4) % 26
                result.append(chr(base + new_offset))
        else:
            result.append(char)
    return ''.join(result)
